# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)

# Replace with your Ethereum node URL
WEB3_NODE_URL = 'https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'
web3 = Web3(Web3.HTTPProvider(WEB3_NODE_URL))

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    message = data.get('message')
    signature = data.get('signature')
    address = data.get('address')

    if not all([message, signature, address]):
        return jsonify({'error': 'Missing required fields'}), 400

    try:
        recovered_address = web3.eth.account.recover_message(message.encode(), signature=signature)
        if recovered_address.lower() == address.lower():
            return jsonify({'authenticated': True})
        else:
            return jsonify({'authenticated': False, 'message': 'Invalid signature'})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)